1	import { HttpStatus } from '@nestjs/common';
2	import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
3	import { Test, TestingModule } from '@nestjs/testing';
4	import { FastifyRequest } from 'fastify';
5	import * as request from 'supertest';
6	
7	import { EnvConfigService } from '@modules/env-config/env-config.service';
8	import { JiraInstallService } from '@modules/jira/jira-install.service';
9	import { JiraController } from '@modules/jira/jira.controller';
10	
11	import type { App } from 'supertest/types';
12	
13	const mockJiraInstallService = {
14		initiateConnect: jest.fn(),
15		handleCallback: jest.fn(),
16		disconnect: jest.fn(),
17	};
18	
19	const mockConfigService = {
20		get: jest.fn().mockReturnValue('http://localhost:3000'),
21	};
22	
23	const mockUser = {
24		user_id: 'user-uuid-1',
25		session_id: 's1',
26		role: 'admin' as const,
27		company_id: 'company-uuid-1',
28	};
29	
30	describe('JiraController (e2e)', () => {
31		let app: NestFastifyApplication;
32		let httpServer: App;
33	
34		beforeAll(async () => {
35			const moduleFixture: TestingModule = await Test.createTestingModule({
36				controllers: [JiraController],
37				providers: [
38					{ provide: JiraInstallService, useValue: mockJiraInstallService },
39					{ provide: EnvConfigService, useValue: mockConfigService },
40				],
41			}).compile();
42	
43			app = moduleFixture.createNestApplication<NestFastifyApplication>(
44				new FastifyAdapter(),
45			);
46	
47			await app.init();
48	
49			app
50				.getHttpAdapter()
51				.getInstance()
52				.addHook(
53					'onRequest',
54					(req: FastifyRequest & { user?: unknown }, _reply: unknown, done: () => void) => {
55						req.user = mockUser;
56						done();
57					},
58				);
59	
60			await app.getHttpAdapter().getInstance().ready();
61	
62			httpServer = app.getHttpServer() as App;
63		});
64	
65		afterAll(async () => {
66			await app.close();
67		});
68	
69		beforeEach(() => jest.clearAllMocks());
70	
71		describe('POST /integrations/jira/connect', () => {
72			it('should return 200 with OAuth URL', async () => {
73				const url = 'https://auth.atlassian.com/authorize?client_id=test';
74				mockJiraInstallService.initiateConnect.mockResolvedValue(url);
75	
76				const res = await request(httpServer).post('/integrations/jira/connect').send();
77	
78				expect(res.status).toBe(HttpStatus.OK);
79				expect(res.body).toEqual({ url });
80				expect(mockJiraInstallService.initiateConnect).toHaveBeenCalledWith({
81					companyId: mockUser.company_id,
82					userId: mockUser.user_id,
83				});
84			});
85	
86			it('should return 500 when service throws', async () => {
87				mockJiraInstallService.initiateConnect.mockRejectedValue(new Error('cache down'));
88	
89				const res = await request(httpServer).post('/integrations/jira/connect').send();
90	
91				expect(res.status).toBe(HttpStatus.INTERNAL_SERVER_ERROR);
92			});
93		});
94	
95		describe('GET /integrations/jira/callback', () => {
96			it('should redirect to frontend with connected=jira on success', async () => {
97				mockJiraInstallService.handleCallback.mockResolvedValue({ _id: 'install-1' });
98	
99				const res = await request(httpServer)
100					.get('/integrations/jira/callback')
101					.query({ code: 'auth-code', state: 'some-state' })
102					.redirects(0);
103	
104				expect(res.status).toBe(HttpStatus.FOUND);
105				expect(res.headers['location']).toContain('connected=jira');
106			});
107	
108			it('should redirect to frontend with error on failure', async () => {
109				mockJiraInstallService.handleCallback.mockRejectedValue(new Error('invalid state'));
110	
111				const res = await request(httpServer)
112					.get('/integrations/jira/callback')
113					.query({ code: 'bad-code', state: 'bad-state' })
114					.redirects(0);
115	
116				expect(res.status).toBe(HttpStatus.FOUND);
117				expect(res.headers['location']).toContain('error=jira_connect_failed');
118			});
119		});
120	
121		describe('DELETE /integrations/jira/installations/:id', () => {
122			it('should return 204 on successful disconnect', async () => {
123				mockJiraInstallService.disconnect.mockResolvedValue(undefined);
124	
125				const res = await request(httpServer)
126					.delete('/integrations/jira/installations/install-uuid-1')
127					.send();
128	
129				expect(res.status).toBe(HttpStatus.NO_CONTENT);
130				expect(mockJiraInstallService.disconnect).toHaveBeenCalledWith({
131					installationDbId: 'install-uuid-1',
132					companyId: mockUser.company_id,
133				});
134			});
135	
136			it('should return 500 when disconnect throws', async () => {
137				mockJiraInstallService.disconnect.mockRejectedValue(new Error('db error'));
138	
139				const res = await request(httpServer)
140					.delete('/integrations/jira/installations/install-uuid-1')
141					.send();
142	
143				expect(res.status).toBe(HttpStatus.INTERNAL_SERVER_ERROR);
144			});
145		});
146	});
